/**
 * 数猪大模型 API 接口层
 *
 * 使用说明：
 * 1. 将 BASE_URL 替换为你的模型服务地址
 * 2. 根据你的接口响应格式修改 analyzeImage() 中的字段映射
 * 3. 如需鉴权，在请求头中加入 Authorization token
 */

import axios from 'axios';

// ============================================================
// 配置区 - 修改这里接入你的真实模型
// ============================================================
const BASE_URL = '/api'; // 生产环境替换为真实地址，如 'https://your-pig-model.com'
const TIMEOUT = 30000; // 超时时间（毫秒）
const API_KEY = ''; // 如需鉴权，填入 API Key

const http = axios.create({
  baseURL: BASE_URL,
  timeout: TIMEOUT,
  headers: {
    ...(API_KEY ? {
      Authorization: `Bearer ${API_KEY}`
    } : {})
  }
});

// 请求拦截器
http.interceptors.request.use(config => config, error => Promise.reject(error));

// 响应拦截器
http.interceptors.response.use(response => response.data, error => {
  const msg = error.response?.data?.message || error.message || '网络请求失败';
  return Promise.reject(new Error(msg));
});

// ============================================================
// 核心接口
// ============================================================

/**
 * 发送图片至数猪模型进行推理
 * @param {File} imageFile - 图片文件对象
 * @param {Function} onProgress - 上传进度回调 (0~100)
 * @returns {Promise<{ count: number, confidence: number, boxes: Array }>}
 */
export async function analyzeImage(imageFile, onProgress) {
  const formData = new FormData();
  formData.append('image', imageFile);
  formData.append('model', 'pig-detector-v1'); // 可选：指定模型版本

  const response = await http.post('/predict', formData, {
    headers: {
      'Content-Type': 'multipart/form-data'
    },
    onUploadProgress: e => {
      if (onProgress && e.total) {
        onProgress(Math.round(e.loaded / e.total * 100));
      }
    }
  });

  // ============================================================
  // 字段映射 - 根据你的接口响应格式修改
  // 假设响应格式如：
  // {
  //   "count": 12,
  //   "confidence": 0.92,
  //   "boxes": [{ "x1":0,"y1":0,"x2":100,"y2":100,"score":0.95 }, ...]
  //   "inference_time_ms": 340
  // }
  // ============================================================
  return {
    count: response.count ?? 0,
    confidence: response.confidence ?? 0,
    // 0~1 浮点数
    boxes: response.boxes ?? [],
    inferenceTime: response.inference_time_ms ?? null
  };
}

/**
 * 健康检查 - 检测模型服务是否在线
 * @returns {Promise<boolean>}
 */
export async function checkHealth() {
  try {
    await http.get('/health', {
      timeout: 5000
    });
    return true;
  } catch {
    return false;
  }
}

// ============================================================
// Mock 函数 - 开发调试用，接入真实 API 后可删除
// ============================================================
export async function analyzeImageMock(imageFile, onProgress) {
  // 模拟上传进度
  for (let p = 0; p <= 100; p += 20) {
    await sleep(150);
    onProgress && onProgress(p);
  }
  // 模拟推理延迟
  await sleep(800 + Math.random() * 600);
  const count = Math.floor(Math.random() * 35) + 1;
  const confidence = 0.72 + Math.random() * 0.26;
  return {
    count,
    confidence,
    boxes: Array.from({
      length: count
    }, (_, i) => ({
      x1: Math.random() * 0.8,
      y1: Math.random() * 0.8,
      x2: Math.random() * 0.2 + 0.1,
      y2: Math.random() * 0.2 + 0.1,
      score: 0.7 + Math.random() * 0.3,
      id: i
    })),
    inferenceTime: Math.floor(200 + Math.random() * 400)
  };
}
function sleep(ms) {
  return new Promise(r => setTimeout(r, ms));
}

